INSERT INTO "Agent" ("id", "name", "title", "photo", "phone", "whatsapp", "email", "languages", "specializations", "communities", "biography", "awards", "rating", "reviewsCount", "activeListings", "soldProperties", "experienceYears", "linkedin", "instagram", "twitter", "order", "published", "createdAt", "updatedAt") VALUES ('cmr5g9zws0000v8j0yx6b8wvx', 'Muhammad Javed Zafar', 'Managing Director', '/team/muhammad-javed-zafar.webp', '+971 4 327 8401', '97143278401', 'muhammad.javed.zafar@royaljubilant.ae', '["English","Urdu","Arabic"]', '["Leadership","Investment Strategy","Portfolio Advisory","Off-Plan Allocations"]', '["Downtown Dubai","Business Bay","Dubai Marina","Palm Jumeirah"]', 'Muhammad Javed Zafar founded Royal Jubilant Real Estate LLC with a vision to bring a more personal, research-led and relationship-driven approach to Dubai property advisory. As Managing Director, he oversees the firm''s strategy, key developer relationships and the senior advisory team. With years of on-the-ground Dubai market experience, he has guided hundreds of families, investors and corporate clients through their property journey — from first acquisition to portfolio diversification.', '["Founder & Managing Director","RERA Certified Broker"]', '4.9', '188', '1', '312', '12', '#', '#', NULL, '1', true, '2026-07-03 21:33:24', '2026-07-11 20:27:02');
INSERT INTO "Agent" ("id", "name", "title", "photo", "phone", "whatsapp", "email", "languages", "specializations", "communities", "biography", "awards", "rating", "reviewsCount", "activeListings", "soldProperties", "experienceYears", "linkedin", "instagram", "twitter", "order", "published", "createdAt", "updatedAt") VALUES ('cmr5g9zwv0001v8j0h0rt2365', 'Maria Raza', 'Administration Manager', '/team/maria-raza.jpeg', '+971 4 327 8401', '97143278401', 'maria.raza@royaljubilant.ae', '["English","Urdu","Hindi"]', '["Operations","Client Relations","Compliance","Document Management"]', '["Business Bay","Downtown Dubai","Dubai Marina"]', 'Maria Raza leads administration and operations at Royal Jubilant, ensuring every transaction, viewing and client engagement runs with precision. She manages the back-office workflow, RERA compliance, agent onboarding and the firm''s document vault — the operational backbone that allows the advisory team to focus on clients.', '["Administration Manager","RERA Compliance Certified"]', '4.9', '96', '2', '0', '7', '#', '#', NULL, '2', true, '2026-07-03 21:33:24', '2026-07-21 13:48:45');
INSERT INTO "Agent" ("id", "name", "title", "photo", "phone", "whatsapp", "email", "languages", "specializations", "communities", "biography", "awards", "rating", "reviewsCount", "activeListings", "soldProperties", "experienceYears", "linkedin", "instagram", "twitter", "order", "published", "createdAt", "updatedAt") VALUES ('cmr5g9zww0002v8j0e8jrg34m', 'Muhammad Naeem Zafar', 'Property Consultant', '/team/muhammad-naeem-zafar.webp', '+971 4 327 8401', '97143278401', 'muhammad.naeem.zafar@royaljubilant.ae', '["English","Urdu","Arabic"]', '["Residential Sales","Apartments","Villas","Buyer Representation"]', '["Dubai Marina","JVC","Business Bay","Dubai Hills Estate"]', 'Muhammad Naeem Zafar is a senior property consultant at Royal Jubilant, specialising in residential sales across Dubai''s mid-market and prime corridors. He has helped dozens of first-time buyers and seasoned investors identify high-yield opportunities, with a particular focus on apartments and villas in family-friendly communities.', '["RERA Certified Property Consultant"]', '4.8', '74', '1', '96', '6', '#', '#', NULL, '3', true, '2026-07-03 21:33:24', '2026-07-21 13:48:45');
