INSERT INTO "BlogPost" ("id", "title", "excerpt", "category", "date", "readTime", "authorName", "image", "content", "published", "authorId", "createdAt", "updatedAt") VALUES ('cmr5fs7e2000xv8y5jsbgsb2a', 'Palm Jumeirah Villa Prices Hit AED 5,100/sqft in Q1 2026', 'Our Q1 2026 prime index shows Palm Jumeirah Signature Villas up 18.4% year-on-year, with frond M and K leading the surge. Here is what is driving demand.', 'Market Insights', '2026-06-28 00:00:00', '6 min', 'Alexander Whitfield', 'https://images.unsplash.com/photo-1518684079-3c830dcef090?auto=format&fit=crop&w=1200&q=80', 'Our Q1 2026 prime index shows Palm Jumeirah Signature Villas up 18.4% year-on-year, with frond M and K leading the surge. Here is what is driving demand.', true, NULL, '2026-07-03 21:19:34', '2026-07-03 21:19:34');
INSERT INTO "BlogPost" ("id", "title", "excerpt", "category", "date", "readTime", "authorName", "image", "content", "published", "authorId", "createdAt", "updatedAt") VALUES ('cmr5fs7e3000yv8y55w315dfx', 'Golden Visa 2026 — What Property Buyers Need to Know', 'The UAE has updated its property-based Golden Visa thresholds. We break down the new AED 2M route, eligible off-plan purchases and family inclusion rules.', 'Guides', '2026-06-20 00:00:00', '8 min', 'Layla Al-Mansoori', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?auto=format&fit=crop&w=1200&q=80', 'The UAE has updated its property-based Golden Visa thresholds. We break down the new AED 2M route, eligible off-plan purchases and family inclusion rules.', true, NULL, '2026-07-03 21:19:34', '2026-07-03 21:19:34');
