INSERT INTO "BlogPost" ("id", "title", "excerpt", "category", "date", "readTime", "authorName", "image", "content", "published", "authorId", "createdAt", "updatedAt") VALUES ('cmr5fs7e60010v8y5wcpmrlyb', 'Creek Harbour vs. Dubai Hills: A 5-Year Investment Case', 'Two of Emaar''s largest masterplans, two very different risk profiles. We compare projected yields, capital growth and exit liquidity for the 2026-2031 horizon.', 'Investment', '2026-05-30 00:00:00', '12 min', 'James Okonkwo', 'https://images.unsplash.com/photo-1606293459339-aa5d34a7b0e1?auto=format&fit=crop&w=1200&q=80', 'Two of Emaar''s largest masterplans, two very different risk profiles. We compare projected yields, capital growth and exit liquidity for the 2026-2031 horizon.', true, NULL, '2026-07-03 21:19:34', '2026-07-03 21:19:34');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmr9yabs30002pdx083tgcxx4', 'Ahmed Al Rashid', 'Business Owner', 'Dubai Marina, UAE', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?auto=format&fit=crop&w=200&q=80', '5', 'I can''t recommend Royal Jubilant enough. I had the pleasure of working with their team — they are truly knowledgeable about the industry and very professional. They consistently kept me up to date about accurate changes in the Dubai market, which helped me make an informed investment decision.', 'Apartment Purchase — Dubai Marina', true, '2026-07-07 01:08:37');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmr9yabs40003pdx0jsoejaz8', 'Sara Khan', 'Marketing Executive', 'Downtown Dubai, UAE', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?auto=format&fit=crop&w=200&q=80', '5', 'Excellent service from start to finish. Muhammad Javed Zafar personally guided me through every step of renting my apartment in Downtown Dubai. The team''s deep knowledge of the market and attention to detail made the entire process smooth and stress-free. Highly recommended!', 'Apartment Rental — Downtown Dubai', true, '2026-07-07 01:08:37');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmr9yabs40004pdx0oh7ady65', 'James Mitchell', 'Investor', 'London, United Kingdom', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=200&q=80', '5', 'As an overseas investor, I needed a real estate partner I could trust. Royal Jubilant delivered beyond expectations — their RERA-certified advisors provided practical, feasible information to capitalize on opportunities for optimal results. They handled everything remotely and made my Dubai property investment effortless.', 'Off-Plan Investment — Creek Harbour', true, '2026-07-07 01:08:37');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmr9yabs50005pdx0p3bhdsn4', 'Fatima Hassan', 'Family Relocation', 'Palm Jumeirah, UAE', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?auto=format&fit=crop&w=200&q=80', '5', 'We relocated our family to Dubai and Royal Jubilant made it seamless. Their team understood exactly what a family needs — they found us the perfect villa in Palm Jumeirah within our budget and handled all the paperwork. Their reputation for excellence and customer satisfaction is well deserved.', 'Family Villa Acquisition — Palm Jumeirah', true, '2026-07-07 01:08:37');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmrdm4pts0000tudtewjyyeb1', 'Aisha Al Marri', 'Verified Client', 'Dubai Marina', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?auto=format&fit=crop&w=200&q=80', '5', 'Found my dream 2BR apartment in Dubai Marina within 48 hours. The team understood exactly what I wanted and negotiated a great rate. Truly five-star service.', 'Tenant', true, '2026-07-09 14:39:25');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmrdm4ptv0001tudthpercg88', 'James Patterson', 'Verified Client', 'Business Bay', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=200&q=80', '5', 'As an expat buying my first property in Dubai, I was nervous. Royal Jubilant made the entire process seamless — from viewings to NOC to handover. Highly recommend.', 'Buyer', true, '2026-07-09 14:39:25');
INSERT INTO "Testimonial" ("id", "name", "role", "location", "avatar", "rating", "quote", "service", "published", "createdAt") VALUES ('cmrdm4ptw0002tudtiisxqlc6', 'Sana Khan', 'Verified Client', 'JVC', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&w=200&q=80', '5', 'I invested in an off-plan project in JVC based on their advice. The ROI has exceeded expectations. Their market knowledge is genuinely unmatched in Dubai.', 'Investor', true, '2026-07-09 14:39:25');
