INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-1', 'What is the minimum property value for a Golden Visa in the UAE?', 'Under the 2026 update, a property purchase of AED 2,000,000 or more qualifies you for the 10-year Golden Visa. Off-plan properties from approved developers are eligible once 20% of the purchase price is paid. Royal Jubilant handles the entire application in-house.', 'buying', '1', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-2', 'Can non-residents buy property in Dubai?', 'Yes. Non-residents can buy freehold property in designated areas of Dubai. Mortgages are available to non-residents at typically 60-70% LTV, and we work with 12 UAE banks to secure the best terms.', 'buying', '2', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-3', 'What are the typical buyer-side costs?', 'Buyer costs include: 4% Dubai Land Department transfer fee, 2% agent fee (Royal Jubilant), AED 4,000 title deed issuance, and a small admin fee. For off-plan, the agent fee is paid by the developer — buyers pay 0%.', 'buying', '3', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-4', 'How long does the buying process take?', 'For a ready property with mortgage: typically 30-45 days. For a cash purchase: 7-14 days. For off-plan: the SPA is signed within 7 days of booking, with payments spread across the construction timeline.', 'buying', '4', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-5', 'What ROI should I expect on a Dubai investment?', 'Yields vary by community and asset class. Prime apartments in Marina/Business Bay deliver 6.5-7.5%, townhouses in Dubai Hills 5.5-6%, and Palm villas 4.5-5.5%. Off-plan in emerging districts like Creek Harbour projects 7-8% on completion.', 'investing', '5', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-6', 'Do you offer property management?', 'Yes. Our in-house property management team handles tenant sourcing, rent collection, maintenance and renewals for an all-in fee of 5% of annual rent. We currently manage 480+ units on behalf of clients.', 'general', '6', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-7', 'What languages does your team speak?', 'Our 12 senior advisors collectively speak English, Arabic, French, German, Italian, Russian, Spanish, Hindi, Urdu, Yoruba and Mandarin. We will match you with an advisor who speaks your language.', 'general', '7', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "Faq" ("id", "question", "answer", "category", "order", "published", "createdAt", "updatedAt") VALUES ('faq-seed-8', 'How do you ensure discretion?', 'We are ISO 27001 certified. All client data is encrypted at rest and in transit, access is role-based, and our advisors operate under strict NDAs. We never list client names publicly without explicit written consent.', 'general', '8', true, '2026-07-07 00:05:43', '2026-07-07 00:05:43');
INSERT INTO "HeroSlide" ("id", "order", "heading1", "heading2", "heading3", "subtitle", "published", "createdAt", "updatedAt") VALUES ('cmrakbzkm0000she559t9usrb', '0', 'Discover Dubai''s most', 'extraordinary addresses', NULL, 'From apartments and villas in family-friendly communities to commercial offices, our portfolio spans every lifestyle and budget — guided by RERA-certified advisors who know Dubai inside-out.', true, '2026-07-07 11:25:46', '2026-07-07 11:25:46');
INSERT INTO "HeroSlide" ("id", "order", "heading1", "heading2", "heading3", "subtitle", "published", "createdAt", "updatedAt") VALUES ('cmrakbzkp0001she5eho4z041', '1', 'Your Dream Property', 'Awaits in Dubai', NULL, 'Discover exceptional homes and investment opportunities with Royal Jubilant Real Estate. Your journey to finding the perfect property starts here.', true, '2026-07-07 11:25:46', '2026-07-07 11:25:46');
INSERT INTO "HeroSlide" ("id", "order", "heading1", "heading2", "heading3", "subtitle", "published", "createdAt", "updatedAt") VALUES ('cmrakbzkq0002she5lang4rx8', '2', 'Premium Real Estate', 'Services in Dubai', NULL, 'Buy, sell, rent or invest in Off Plan properties with Dubai''s trusted real estate broker. RERA-certified advisors, deep local knowledge, and a commitment to smoother transactions.', true, '2026-07-07 11:25:46', '2026-07-07 11:25:46');
INSERT INTO "HeroSlide" ("id", "order", "heading1", "heading2", "heading3", "subtitle", "published", "createdAt", "updatedAt") VALUES ('cmrakbzks0003she541g87hqs', '3', 'Invest in Dubai''s', 'Most Exciting', 'Off-Plan Projects', 'Pre-launch allocations from Emaar, DAMAC, Omniyat and Sobha with flexible payment plans. Invest in Dubai''s most exciting upcoming developments before they hit the public market.', true, '2026-07-07 11:25:46', '2026-07-07 11:25:46');
INSERT INTO "HeroSlide" ("id", "order", "heading1", "heading2", "heading3", "subtitle", "published", "createdAt", "updatedAt") VALUES ('cmrakbzkt0004she57x8arrwt', '4', 'Dubai''s Premier', 'Luxury Property', 'Destination', 'A discreet portfolio of trophy assets above AED 15M — Signature Villas, branded penthouses and one-off architectural masterpieces. Available to qualified clients by private appointment.', true, '2026-07-07 11:25:46', '2026-07-07 11:25:46');
