INSERT INTO "SiteSetting" ("id", "key", "value", "category", "updatedAt") VALUES ('cmran4ifl0002shtk22hrk1up', 'offplan.about.subtitle', 'Dubai''s residential real estate market recorded AED 139.1 billion in transactions in Q1 2026, with Off Plan properties accounting for 73% of all residential sales activity, according to Cavendish Maxwell. Flexible payment plans, developer incentives, and sustained investor demand continue to drive the Off Plan market. Whether you''re investing for rental income, capital growth, a Golden Visa, or a future home, Royal Jubilant gives you early access to the highest-performing projects across the city.', 'offplan', '2026-07-07 12:43:56');
